mapper.select:
SELECT *
FROM service_order
WHERE student_user_id = #{studentUserId}
  AND org_id = #{orgId}
  AND team_id = #{teamId}
ORDER BY updated_at DESC, id DESC
LIMIT 1

mapper.update:
UPDATE service_order
SET order_status = 'CLOSED',
    closed_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND student_user_id = #{studentUserId}
  AND order_status IN ('PENDING_QUOTE', 'WAITING_PAYMENT')

UPDATE service_order
SET order_status = 'REFUND_REQUESTED'
WHERE id = #{id}
  AND student_user_id = #{studentUserId}
  AND order_status IN ('IN_SERVICE', 'COMPLETED')
